mapper.select:
SELECT T.label, SUM(CASE WHEN T.type = 'DONATE' THEN 1 ELSE 0 END) as donateCnt, SUM(CASE WHEN T.type = 'VOL' THEN 1 ELSE 0 END) as volCnt FROM ( SELECT CAST(DATE_FORMAT(REG_DT,
'%m-%d' '%Y-%m' '%u주차'
) AS CHAR) as label, 'DONATE' as type FROM TB_DONATION_PAYMENT UNION ALL SELECT CAST(DATE_FORMAT(REG_DT,
'%m-%d' '%Y-%m' '%u주차'
) AS CHAR) as label, 'VOL' as type FROM TB_VOLUNTEER_APPLY ) T GROUP BY label ORDER BY label LIMIT 10
